export interface Span {
  file: string;
  start: number;
  end: number;
}

export interface Identifier {
  kind: 'Identifier';
  name: string;
  span?: Span;
}

export interface Literal {
  kind: 'Literal';
  value: string | number | boolean;
  span?: Span;
}

export interface CallExpression {
  kind: 'CallExpression';
  callee: Identifier;
  arguments: Expression[];
  span?: Span;
}

export interface UnaryExpression {
  kind: 'UnaryExpression';
  operator: '!' | 'not';
  operand: Expression;
  span?: Span;
}

export interface BinaryExpression {
  kind: 'BinaryExpression';
  operator: string;
  left: Expression;
  right: Expression;
  span?: Span;
}

export interface IfExpression {
  kind: 'IfExpression';
  condition: Expression;
  thenBranch: Expression;
  elseBranch: Expression;
  span?: Span;
}

export interface LetExpression {
  kind: 'LetExpression';
  name: Identifier;
  value: Expression;
  body: Expression;
  span?: Span;
}

export type Expression =
  | Identifier
  | Literal
  | CallExpression
  | UnaryExpression
  | BinaryExpression
  | IfExpression
  | LetExpression;

export interface Statement {
  kind: string;
  span?: Span;
}

export interface Declaration extends Statement {
  kind: 'Declaration';
  name: Identifier;
  value: Expression;
}

export type ForeignTarget = 'cpp';

export type ForeignPrimitiveType =
  | 'i32'
  | 'f64'
  | 'bool'
  | 'string'
  | 'void'
  | 'handle'
  | 'f64buf'
  | 'i32buf';

export interface ForeignSignature {
  params: ForeignPrimitiveType[];
  result: ForeignPrimitiveType;
}

export interface FunctionSignature {
  params: ForeignPrimitiveType[];
  result: ForeignPrimitiveType;
}

export interface FunctionDeclaration extends Statement {
  kind: 'FunctionDeclaration';
  name: Identifier;
  params: Identifier[];
  signature: FunctionSignature;
  body: Expression;
}

export interface ForeignImport extends Statement {
  kind: 'ForeignImport';
  target: ForeignTarget;
  name: Identifier;
  symbol: string;
  signature: ForeignSignature;
}

export type TopLevel =
  | Declaration
  | FunctionDeclaration
  | ForeignImport;

import { Program, Module } from '../core/program';
import { Declaration, Expression, Span, ForeignImport, ForeignSignature, FunctionSignature, ForeignPrimitiveType } from '../core/ast';
import { Diagnostic } from '../core/diagnostic';

export interface ParseResult {
  program?: Program;
  diagnostics: Diagnostic[];
}

const VALID_FFI = ['i32', 'f64', 'bool', 'string', 'void', 'handle', 'f64buf', 'i32buf'];
const BINARY_PRECEDENCE: string[][] = [
  ['||'],
  ['&&'],
  ['==', '!=', '<=', '>=', '<', '>'],
  ['+', '-'],
  ['*', '/'],
];

function isValidFFIType(t: string): boolean {
  return VALID_FFI.includes(t);
}

function parseSignature(text: string): FunctionSignature | undefined {
  const parts = text.split('->').map(s => s.trim());
  if (parts.length < 2) return undefined;
  const resultType = parts[parts.length - 1];
  const paramTypes = parts.slice(0, -1);
  if (!isValidFFIType(resultType) || paramTypes.some(t => !isValidFFIType(t))) return undefined;
  if (paramTypes.includes('void')) return undefined;
  return { params: paramTypes as ForeignPrimitiveType[], result: resultType as ForeignPrimitiveType };
}

function stripOuterParens(text: string): string {
  let s = text.trim();
  while (s.startsWith('(') && s.endsWith(')')) {
    let depth = 0;
    let wraps = true;
    for (let i = 0; i < s.length; i++) {
      const ch = s[i];
      if (ch === '(') depth++;
      if (ch === ')') depth--;
      if (depth === 0 && i < s.length - 1) {
        wraps = false;
        break;
      }
    }
    if (!wraps) break;
    s = s.slice(1, -1).trim();
  }
  return s;
}

function findKeywordAtTopLevel(text: string, keyword: string): number {
  let depth = 0;
  let inString = false;
  for (let i = 0; i <= text.length - keyword.length; i++) {
    const ch = text[i];
    if (ch === '"') inString = !inString;
    if (inString) continue;
    if (ch === '(') depth++;
    if (ch === ')') depth--;
    if (depth !== 0) continue;
    if (text.slice(i, i + keyword.length) === keyword) {
      const before = i === 0 ? ' ' : text[i - 1];
      const after = i + keyword.length >= text.length ? ' ' : text[i + keyword.length];
      if (/\s/.test(before) && /\s/.test(after)) return i;
    }
  }
  return -1;
}

function findBindingEqualsAtTopLevel(text: string): number {
  let depth = 0;
  let inString = false;
  for (let i = 0; i < text.length; i++) {
    const ch = text[i];
    if (ch === '"') inString = !inString;
    if (inString) continue;
    if (ch === '(') depth++;
    if (ch === ')') depth--;
    if (depth !== 0 || ch !== '=') continue;
    const prev = i > 0 ? text[i - 1] : '';
    const next = i + 1 < text.length ? text[i + 1] : '';
    if (prev === '<' || prev === '>' || prev === '!' || prev === '=' || next === '=') continue;
    return i;
  }
  return -1;
}

function findOperatorAtTopLevel(text: string, ops: string[]): { index: number; op: string } | undefined {
  let depth = 0;
  let inString = false;
  for (let i = text.length - 1; i >= 0; i--) {
    const ch = text[i];
    if (ch === '"') inString = !inString;
    if (inString) continue;
    if (ch === ')') depth++;
    if (ch === '(') depth--;
    if (depth !== 0) continue;
    for (const op of ops) {
      const start = i - op.length + 1;
      if (start < 0) continue;
      if (text.slice(start, i + 1) !== op) continue;
      const prev = start > 0 ? text[start - 1] : '';
      if ((op === '-' || op === '+') && (start === 0 || ['+', '-', '*', '/', '<', '>', '=', '!', '('].includes(prev))) continue;
      return { index: start, op };
    }
  }
  return undefined;
}

function splitArgs(text: string): string[] {
  const out: string[] = [];
  let depth = 0;
  let inString = false;
  let start = 0;
  for (let i = 0; i < text.length; i++) {
    const ch = text[i];
    if (ch === '"') inString = !inString;
    if (inString) continue;
    if (ch === '(') depth++;
    if (ch === ')') depth--;
    if (ch === ',' && depth === 0) {
      out.push(text.slice(start, i).trim());
      start = i + 1;
    }
  }
  const last = text.slice(start).trim();
  if (last.length > 0) out.push(last);
  return out;
}

function parseExpression(text: string, span: Span): Expression | undefined {
  const s = stripOuterParens(text);
  if (s.startsWith('let ')) {
    const inIdx = findKeywordAtTopLevel(s, 'in');
    if (inIdx > 0) {
      const binding = s.slice(4, inIdx).trim();
      const eqIdx = findBindingEqualsAtTopLevel(binding);
      if (eqIdx > 0) {
        const nameText = binding.slice(0, eqIdx).trim();
        const valueText = binding.slice(eqIdx + 1).trim();
        const bodyText = s.slice(inIdx + 2).trim();
        if (/^[A-Za-z_][A-Za-z0-9_]*$/.test(nameText)) {
          const value = parseExpression(valueText, span);
          const body = parseExpression(bodyText, span);
          if (value && body) return { kind: 'LetExpression', name: { kind: 'Identifier', name: nameText, span }, value, body, span };
        }
      }
    }
  }
  if (s.startsWith('if ')) {
    const thenIdx = findKeywordAtTopLevel(s, 'then');
    if (thenIdx > 0) {
      const elseIdx = findKeywordAtTopLevel(s.slice(thenIdx + 4), 'else');
      if (elseIdx >= 0) {
        const condText = s.slice(3, thenIdx).trim();
        const thenText = s.slice(thenIdx + 4, thenIdx + 4 + elseIdx).trim();
        const elseText = s.slice(thenIdx + 4 + elseIdx + 4).trim();
        const condition = parseExpression(condText, span);
        const thenBranch = parseExpression(thenText, span);
        const elseBranch = parseExpression(elseText, span);
        if (condition && thenBranch && elseBranch) return { kind: 'IfExpression', condition, thenBranch, elseBranch, span };
      }
    }
  }
  for (const ops of BINARY_PRECEDENCE) {
    const found = findOperatorAtTopLevel(s, ops);
    if (found) {
      const left = parseExpression(s.slice(0, found.index).trim(), span);
      const right = parseExpression(s.slice(found.index + found.op.length).trim(), span);
      if (left && right) return { kind: 'BinaryExpression', operator: found.op, left, right, span };
    }
  }
  if (s.startsWith('!')) {
    const operand = parseExpression(s.slice(1).trim(), span);
    if (operand) return { kind: 'UnaryExpression', operator: '!', operand, span };
    return undefined;
  }
  if (s.startsWith('not ')) {
    const operand = parseExpression(s.slice(4).trim(), span);
    if (operand) return { kind: 'UnaryExpression', operator: 'not', operand, span };
    return undefined;
  }
  if (s === 'true' || s === 'false') return { kind: 'Literal', value: s === 'true', span };
  if (!isNaN(Number(s))) return { kind: 'Literal', value: Number(s), span };
  if (s.startsWith('"') && s.endsWith('"')) return { kind: 'Literal', value: s.slice(1, -1), span };
  const callMatch = s.match(/^([A-Za-z_][A-Za-z0-9_]*)\s*\((.*)\)$/);
  if (callMatch) {
    const callee = { kind: 'Identifier' as const, name: callMatch[1], span };
    const args = callMatch[2].trim().length === 0 ? [] : splitArgs(callMatch[2]).map(a => parseExpression(a, span));
    if (args.every(Boolean)) return { kind: 'CallExpression', callee, arguments: args as Expression[], span };
    return undefined;
  }
  if (/^[A-Za-z_][A-Za-z0-9_]*$/.test(s)) return { kind: 'Identifier', name: s, span };
  return undefined;
}

function flushPendingSignatures(moduleName: string, pending: Map<string, FunctionSignature>, diagnostics: Diagnostic[]): void {
  for (const name of pending.keys()) diagnostics.push({ message: `Dangling type signature for ${name} in module ${moduleName}` });
  pending.clear();
}

export function parse(source: string, filename = 'input.ls'): ParseResult {
  const lines = source.split(/\r?\n/);
  let currentModule: Module | null = null;
  const modules: Module[] = [];
  const diagnostics: Diagnostic[] = [];
  const pendingSignatures = new Map<string, FunctionSignature>();

  for (let i = 0; i < lines.length; i++) {
    const rawLine = lines[i];
    const line = rawLine.trim();
    if (!line || line.startsWith('//')) continue;

    const moduleMatch = line.match(/^module\s+([A-Za-z_][A-Za-z0-9_]*)$/);
    if (moduleMatch) {
      if (currentModule) {
        flushPendingSignatures(currentModule.name, pendingSignatures, diagnostics);
        modules.push(currentModule);
      }
      currentModule = { kind: 'Module', name: moduleMatch[1], declarations: [] };
      pendingSignatures.clear();
      continue;
    }

    const typeSigMatch = line.match(/^([A-Za-z_][A-Za-z0-9_]*)\s*:\s*(.+)$/);
    if (typeSigMatch && currentModule) {
      const signature = parseSignature(typeSigMatch[2].trim());
      if (!signature) {
        diagnostics.push({ message: `Invalid type signature at line ${i+1}` });
        continue;
      }
      if (pendingSignatures.has(typeSigMatch[1])) {
        diagnostics.push({ message: `Duplicate type signature for ${typeSigMatch[1]} at line ${i+1}` });
        continue;
      }
      pendingSignatures.set(typeSigMatch[1], signature);
      continue;
    }

    const foreignMatch = line.match(/^foreign\s+cpp\s+([A-Za-z_][A-Za-z0-9_]*)\s*:\s*(.+?)\s*=\s*"([^"]+)"$/);
    if (foreignMatch && currentModule) {
      const localName = foreignMatch[1];
      const signature = parseSignature(foreignMatch[2].trim());
      const symbol = foreignMatch[3];
      if (!signature) {
        diagnostics.push({ message: `Invalid foreign signature at line ${i+1}` });
        continue;
      }
      const imp: ForeignImport = {
        kind: 'ForeignImport',
        target: 'cpp',
        name: { kind: 'Identifier', name: localName },
        symbol,
        signature: signature as ForeignSignature
      };
      currentModule.declarations.push(imp);
      continue;
    }

    const functionMatch = line.match(/^([A-Za-z_][A-Za-z0-9_]*)(\s+[A-Za-z_][A-Za-z0-9_]*)+\s*=\s*(.+)$/);
    if (functionMatch && currentModule) {
      const eqIdx = line.indexOf('=');
      const left = line.slice(0, eqIdx).trim().split(/\s+/);
      const name = left[0];
      const params = left.slice(1).map(p => ({ kind: 'Identifier' as const, name: p }));
      const signature = pendingSignatures.get(name);
      if (!signature) {
        diagnostics.push({ message: `Missing type signature for function ${name} at line ${i+1}` });
        continue;
      }
      if (signature.params.length !== params.length) {
        diagnostics.push({ message: `Parameter count does not match signature for ${name} at line ${i+1}` });
        pendingSignatures.delete(name);
        continue;
      }
      const span: Span = { file: filename, start: i, end: i };
      const body = parseExpression(line.slice(eqIdx + 1).trim(), span);
      if (!body) {
        diagnostics.push({ message: `Invalid function body at line ${i+1}` });
        pendingSignatures.delete(name);
        continue;
      }
      currentModule.declarations.push({
        kind: 'FunctionDeclaration',
        name: { kind: 'Identifier', name },
        params,
        signature,
        body,
        span
      });
      pendingSignatures.delete(name);
      continue;
    }

    const declMatch = line.match(/^([A-Za-z_][A-Za-z0-9_]*)\s*=\s*(.+)$/);
    if (declMatch && currentModule) {
      const name = declMatch[1];
      const valueStr = declMatch[2].trim();
      const span: Span = { file: filename, start: i, end: i };
      const value = parseExpression(valueStr, span);
      if (!value) {
        diagnostics.push({ message: `Invalid expression at line ${i+1}` });
        continue;
      }
      const decl: Declaration = {
        kind: 'Declaration',
        name: { kind: 'Identifier', name },
        value
      };
      currentModule.declarations.push(decl);
      continue;
    }

    diagnostics.push({ message: `Invalid line at ${i+1}: ${rawLine.trim()}` });
  }

  if (currentModule) {
    flushPendingSignatures(currentModule.name, pendingSignatures, diagnostics);
    modules.push(currentModule);
  }

  return {
    program: diagnostics.length === 0 ? { kind: 'Program', modules } : undefined,
    diagnostics
  };
}

import { Program } from './program';
import { Diagnostic } from './diagnostic';
import { CallExpression, Expression, ForeignImport, ForeignPrimitiveType, FunctionDeclaration, FunctionSignature, UnaryExpression } from './ast';

type TypeName = ForeignPrimitiveType;

interface Scope {
  topLevel: Set<string>;
  locals: Map<string, TypeName>;
  signatures: Map<string, FunctionSignature>;
  values: Map<string, TypeName>;
}

export function checkProgram(program: Program): { diagnostics: Diagnostic[] } {
  const diagnostics: Diagnostic[] = [];
  const names = new Set<string>();
  const signatures = new Map<string, FunctionSignature>();
  const values = new Map<string, TypeName>();

  for (const mod of program.modules) {
    names.clear();
    signatures.clear();
    values.clear();

    for (const item of mod.declarations) {
      const name = item.name.name;
      if (names.has(name)) diagnostics.push({ message: `Duplicate top-level name: ${name}` });
      names.add(name);
      if (item.kind === 'FunctionDeclaration') signatures.set(name, (item as FunctionDeclaration).signature);
      if (item.kind === 'ForeignImport') signatures.set(name, (item as ForeignImport).signature);
    }

    for (const item of mod.declarations) {
      if (item.kind === 'ForeignImport') {
        const foreign = item as ForeignImport;
        if (foreign.signature.params.includes('void')) diagnostics.push({ message: `void cannot be a parameter type for ${foreign.name.name}` });
      }
    }

    for (const item of mod.declarations) {
      if (item.kind === 'FunctionDeclaration') {
        const fn = item as FunctionDeclaration;
        if (fn.signature.params.length !== fn.params.length) diagnostics.push({ message: `Wrong parameter count for ${fn.name.name}` });
        const localTypes = new Map<string, TypeName>();
        for (let i = 0; i < fn.params.length; i++) {
          const param = fn.params[i];
          if (localTypes.has(param.name)) diagnostics.push({ message: `Duplicate parameter ${param.name} in ${fn.name.name}` });
          localTypes.set(param.name, fn.signature.params[i]);
        }
        const bodyType = inferExpression(fn.body, { topLevel: names, locals: localTypes, signatures, values }, diagnostics);
        if (bodyType && !typeCompatible(bodyType, fn.signature.result)) diagnostics.push({ message: `Function ${fn.name.name} returns ${bodyType}, expected ${fn.signature.result}` });
      }
      if (item.kind === 'Declaration') {
        const t = inferExpression(item.value, { topLevel: names, locals: new Map<string, TypeName>(), signatures, values }, diagnostics);
        if (t) values.set(item.name.name, t);
      }
    }
  }
  return { diagnostics };
}

function inferExpression(expr: Expression, scope: Scope, diagnostics: Diagnostic[]): TypeName | undefined {
  if (expr.kind === 'Literal') {
    if (typeof expr.value === 'boolean') return 'bool';
    if (typeof expr.value === 'string') return 'string';
    if (typeof expr.value === 'number') return Number.isInteger(expr.value) ? 'i32' : 'f64';
  }
  if (expr.kind === 'Identifier') {
    if (scope.locals.has(expr.name)) return scope.locals.get(expr.name);
    if (scope.values.has(expr.name)) return scope.values.get(expr.name);
    if (scope.signatures.has(expr.name)) diagnostics.push({ message: `Function used as value: ${expr.name}` });
    else if (!scope.topLevel.has(expr.name)) diagnostics.push({ message: `Unknown identifier: ${expr.name}` });
    else diagnostics.push({ message: `Unknown value type: ${expr.name}` });
    return undefined;
  }
  if (expr.kind === 'CallExpression') {
    const call = expr as CallExpression;
    const callee = call.callee.name;
    const signature = scope.signatures.get(callee);
    if (!scope.topLevel.has(callee)) {
      diagnostics.push({ message: `Unknown function: ${callee}` });
    } else if (!signature) {
      diagnostics.push({ message: `Cannot call non-function value: ${callee}` });
    } else {
      if (call.arguments.length !== signature.params.length) diagnostics.push({ message: `Wrong argument count for ${callee}` });
      for (let i = 0; i < call.arguments.length; i++) {
        const actual = inferExpression(call.arguments[i], scope, diagnostics);
        const expected = signature.params[i];
        if (actual && expected && !typeCompatible(actual, expected)) diagnostics.push({ message: `Argument ${i + 1} for ${callee} has type ${actual}, expected ${expected}` });
      }
      return signature.result;
    }
    for (const arg of call.arguments) inferExpression(arg, scope, diagnostics);
    return undefined;
  }
  if (expr.kind === 'UnaryExpression') {
    const unary = expr as UnaryExpression;
    const operand = inferExpression(unary.operand, scope, diagnostics);
    if (operand && operand !== 'bool') diagnostics.push({ message: `Unary ${unary.operator} expects bool operand, got ${operand}` });
    return 'bool';
  }
  if (expr.kind === 'BinaryExpression') {
    const left = inferExpression(expr.left, scope, diagnostics);
    const right = inferExpression(expr.right, scope, diagnostics);
    return inferBinaryType(expr.operator, left, right, diagnostics);
  }
  if (expr.kind === 'IfExpression') {
    const condition = inferExpression(expr.condition, scope, diagnostics);
    const thenType = inferExpression(expr.thenBranch, scope, diagnostics);
    const elseType = inferExpression(expr.elseBranch, scope, diagnostics);
    if (condition && condition !== 'bool') diagnostics.push({ message: `If condition has type ${condition}, expected bool` });
    if (thenType && elseType && !typeCompatible(thenType, elseType) && !typeCompatible(elseType, thenType)) diagnostics.push({ message: `If branches have different types: ${thenType} and ${elseType}` });
    if (thenType && elseType) return thenType === 'f64' || elseType === 'f64' ? 'f64' : thenType;
    return undefined;
  }
  if (expr.kind === 'LetExpression') {
    const valueType = inferExpression(expr.value, scope, diagnostics);
    const innerLocals = new Map(scope.locals);
    if (valueType) innerLocals.set(expr.name.name, valueType);
    return inferExpression(expr.body, { topLevel: scope.topLevel, locals: innerLocals, signatures: scope.signatures, values: scope.values }, diagnostics);
  }
  return undefined;
}

function inferBinaryType(op: string, left: TypeName | undefined, right: TypeName | undefined, diagnostics: Diagnostic[]): TypeName | undefined {
  if (!left || !right) return undefined;
  if (['+', '-', '*', '/'].includes(op)) {
    if (!isNumeric(left) || !isNumeric(right)) {
      diagnostics.push({ message: `Operator ${op} expects numeric operands, got ${left} and ${right}` });
      return undefined;
    }
    return left === 'f64' || right === 'f64' ? 'f64' : 'i32';
  }
  if (['&&', '||'].includes(op)) {
    if (left !== 'bool' || right !== 'bool') diagnostics.push({ message: `Operator ${op} expects bool operands, got ${left} and ${right}` });
    return 'bool';
  }
  if (['<', '>', '<=', '>='].includes(op)) {
    if (!isNumeric(left) || !isNumeric(right)) diagnostics.push({ message: `Operator ${op} expects numeric operands, got ${left} and ${right}` });
    return 'bool';
  }
  if (['==', '!='].includes(op)) {
    if (!typeCompatible(left, right) && !typeCompatible(right, left)) diagnostics.push({ message: `Operator ${op} expects matching operands, got ${left} and ${right}` });
    return 'bool';
  }
  diagnostics.push({ message: `Unknown binary operator: ${op}` });
  return undefined;
}

function typeCompatible(actual: TypeName, expected: TypeName): boolean {
  return actual === expected || (actual === 'i32' && expected === 'f64');
}

function isNumeric(t: TypeName): boolean {
  return t === 'i32' || t === 'f64';
}

import { Program } from '../core/program';
import { Declaration, ForeignImport, CallExpression, FunctionDeclaration } from '../core/ast';

export function emitTypeScript(program: Program): string {
  const hasFFI = program.modules.some(m => m.declarations.some(d => d.kind === 'ForeignImport'));

  let out = hasFFI ? `import { CppForeignRuntime } from '../runtime/cppForeign';

` : '';

  for (const mod of program.modules) {
    const foreignNames = new Set(mod.declarations.filter(d => d.kind === 'ForeignImport').map(d => d.name.name));
    out += `// Module: ${mod.name}\n\n`;

    for (const item of mod.declarations) {
      if (item.kind === 'ForeignImport') {
        const f = item as ForeignImport;
        const params = f.signature.params.map((t, i) => `arg${i}: ${mapTsType(t)}`).join(', ');
        const ret = mapTsType(f.signature.result);
        out += `export function ${f.name.name}(runtime: CppForeignRuntime, ${params}): ${ret} {
`;
        out += `  return runtime.call({ symbol: '${f.symbol}', args: [${f.signature.params.map((_,i)=>`arg${i}`).join(', ')}] }) as ${ret};
`;
        out += `}

`;
      }
    }

    for (const item of mod.declarations) {
      if (item.kind === 'FunctionDeclaration') {
        const fn = item as FunctionDeclaration;
        const params = fn.params.map((p, i) => `${p.name}: ${mapTsType(fn.signature.params[i])}`).join(', ');
        out += `export function ${fn.name.name}(${params}): ${mapTsType(fn.signature.result)} {
`;
        out += `  return ${emitExpr(fn.body, foreignNames)};
`;
        out += `}

`;
      }
      if (item.kind === 'Declaration') {
        const d = item as Declaration;
        if (d.value.kind === 'CallExpression' && foreignNames.has((d.value as CallExpression).callee.name)) {
          const call = d.value as CallExpression;
          const args = call.arguments.map(a => emitExpr(a, foreignNames)).join(', ');
          out += `export function ${d.name.name}(runtime: CppForeignRuntime) {
`;
          out += `  return ${call.callee.name}(runtime, ${args});
`;
          out += `}

`;
        } else {
          out += `export const ${d.name.name} = ${emitExpr(d.value, foreignNames)};
`;
        }
      }
    }
  }
  return out.trim();
}

function mapTsType(t: string): string {
  if (t === 'i32' || t === 'f64' || t === 'handle' || t === 'f64buf' || t === 'i32buf') return 'number';
  if (t === 'bool') return 'boolean';
  if (t === 'string') return 'string';
  if (t === 'void') return 'null';
  return 'unknown';
}

function expressionKind(e: any): string {
  if (e && typeof e.kind === 'string') return e.kind;
  return typeof e;
}

function emitExpr(e: any, foreignNames = new Set<string>()): string {
  if (e.kind === 'Literal') return JSON.stringify(e.value);
  if (e.kind === 'Identifier') return e.name;
  if (e.kind === 'CallExpression') {
    const c = e;
    if (foreignNames.has(c.callee.name)) throw new Error(`TypeScript backend unsupported foreign call placement: ${c.callee.name}`);
    return `${c.callee.name}(${c.arguments.map((arg: any) => emitExpr(arg, foreignNames)).join(', ')})`;
  }
  if (e.kind === 'UnaryExpression') {
    const op = e.operator === 'not' ? '!' : e.operator;
    return `(${op}${emitExpr(e.operand, foreignNames)})`;
  }
  if (e.kind === 'BinaryExpression') return `(${emitExpr(e.left, foreignNames)} ${e.operator} ${emitExpr(e.right, foreignNames)})`;
  if (e.kind === 'IfExpression') return `(${emitExpr(e.condition, foreignNames)} ? ${emitExpr(e.thenBranch, foreignNames)} : ${emitExpr(e.elseBranch, foreignNames)})`;
  if (e.kind === 'LetExpression') return `(() => { const ${e.name.name} = ${emitExpr(e.value, foreignNames)}; return ${emitExpr(e.body, foreignNames)}; })()`;
  throw new Error(`TypeScript backend unsupported expression kind: ${expressionKind(e)}`);
}

import { Program } from '../core/program';
import { Declaration, ForeignImport, CallExpression, Literal, FunctionDeclaration } from '../core/ast';

export function emitHaskell(program: Program): string {
  let out = '';
  let needsCString = false;
  let needsPtr = false;
  let needsCDouble = false;
  let needsCInt = false;

  for (const mod of program.modules) {
    const foreignNames = new Set(mod.declarations.filter(d => d.kind === 'ForeignImport').map(d => d.name.name));
    out += `-- Module: ${mod.name}
`;

    for (const item of mod.declarations) {
      if (item.kind === 'ForeignImport') {
        const f = item as ForeignImport;
        const allTypes = [...f.signature.params, f.signature.result];
        if (allTypes.includes('string')) needsCString = true;
        if (allTypes.some(isPointerBackedType)) needsPtr = true;
        if (allTypes.includes('f64buf')) needsCDouble = true;
        if (allTypes.includes('i32buf')) needsCInt = true;
        const params = f.signature.params.map(t => mapHaskellType(t));
        const ret = mapHaskellIOResultType(f.signature.result);
        const sig = params.length > 0 ? `${params.join(' -> ')} -> IO ${ret}` : `IO ${ret}`;
        out += `foreign import ccall "${f.symbol}" ${f.name.name} :: ${sig}

`;
      }
    }

    for (const item of mod.declarations) {
      if (item.kind === 'FunctionDeclaration') {
        const fn = item as FunctionDeclaration;
        const params = fn.signature.params.map(t => mapHaskellType(t));
        const sig = [...params, mapHaskellType(fn.signature.result)].join(' -> ');
        out += `${fn.name.name} :: ${sig}
`;
        out += `${fn.name.name} ${fn.params.map(p => p.name).join(' ')} = ${emitHaskellExpr(fn.body, foreignNames)}

`;
      }
      if (item.kind === 'Declaration') {
        const d = item as Declaration;
        if (d.value.kind === 'CallExpression' && foreignNames.has((d.value as CallExpression).callee.name)) {
          const call = d.value as CallExpression;
          const foreign = mod.declarations.find(f => f.kind === 'ForeignImport' && f.name.name === call.callee.name) as ForeignImport | undefined;
          const retType = foreign ? mapHaskellIOResultType(foreign.signature.result) : 'Int';
          out += `${d.name.name} :: IO ${retType}
`;
          if (foreign && foreign.signature.params.includes('string') && isStringLiteral(call.arguments[0])) {
            out += `${d.name.name} = withCString ${JSON.stringify(call.arguments[0].value)} ${call.callee.name}

`;
          } else {
            const args = call.arguments.map(a => emitHaskellExpr(a, foreignNames)).join(' ');
            out += `${d.name.name} = ${call.callee.name} ${args}

`;
          }
        } else {
          out += `${d.name.name} = ${emitHaskellExpr(d.value, foreignNames)}

`;
        }
      }
    }
  }

  const imports: string[] = [];
  if (needsCString) imports.push('import Foreign.C.String (CString, withCString)');
  if (needsPtr) imports.push('import Foreign.Ptr (Ptr)');
  if (needsCDouble || needsCInt) {
    const types = [needsCDouble ? 'CDouble' : undefined, needsCInt ? 'CInt' : undefined].filter(Boolean).join(', ');
    imports.push(`import Foreign.C.Types (${types})`);
  }
  if (imports.length > 0) out = `${imports.join('\n')}

${out}`;
  return out.trim();
}

function isStringLiteral(e: any): e is Literal {
  return e && e.kind === 'Literal' && typeof e.value === 'string';
}

function isPointerBackedType(t: string): boolean {
  return t === 'handle' || t === 'f64buf' || t === 'i32buf';
}

function mapHaskellType(t: string): string {
  if (t === 'i32') return 'Int';
  if (t === 'f64') return 'Double';
  if (t === 'bool') return 'Bool';
  if (t === 'string') return 'CString';
  if (t === 'handle') return 'Ptr ()';
  if (t === 'f64buf') return 'Ptr CDouble';
  if (t === 'i32buf') return 'Ptr CInt';
  return '()';
}

function mapHaskellIOResultType(t: string): string {
  const mapped = mapHaskellType(t);
  return isPointerBackedType(t) ? `(${mapped})` : mapped;
}

function mapHaskellBinaryOperator(op: string): string {
  if (op === '!=') return '/=';
  return op;
}

function parenIfNeeded(s: string): string {
  return s.startsWith('(') && s.endsWith(')') ? s : `(${s})`;
}

function expressionKind(e: any): string {
  if (e && typeof e.kind === 'string') return e.kind;
  return typeof e;
}

function isAtomicHaskellOperand(e: any): boolean {
  return e.kind === 'Literal' || e.kind === 'Identifier';
}

function emitHaskellExpr(e: any, foreignNames = new Set<string>()): string {
  if (e.kind === 'Literal') {
    if (typeof e.value === 'boolean') return e.value ? 'True' : 'False';
    if (typeof e.value === 'string') return JSON.stringify(e.value);
    return String(e.value);
  }
  if (e.kind === 'Identifier') return e.name;
  if (e.kind === 'CallExpression') {
    if (foreignNames.has(e.callee.name)) throw new Error(`Haskell backend unsupported foreign call placement: ${e.callee.name}`);
    const args = e.arguments.map((arg: any) => {
      const emitted = emitHaskellExpr(arg, foreignNames);
      if (arg.kind === 'Literal' || arg.kind === 'Identifier') return emitted;
      return parenIfNeeded(emitted);
    }).join(' ');
    return args.length > 0 ? `${e.callee.name} ${args}` : e.callee.name;
  }
  if (e.kind === 'UnaryExpression') {
    const emitted = emitHaskellExpr(e.operand, foreignNames);
    return `not ${isAtomicHaskellOperand(e.operand) ? emitted : parenIfNeeded(emitted)}`;
  }
  if (e.kind === 'BinaryExpression') return `(${emitHaskellExpr(e.left, foreignNames)} ${mapHaskellBinaryOperator(e.operator)} ${emitHaskellExpr(e.right, foreignNames)})`;
  if (e.kind === 'IfExpression') return `(if ${emitHaskellExpr(e.condition, foreignNames)} then ${emitHaskellExpr(e.thenBranch, foreignNames)} else ${emitHaskellExpr(e.elseBranch, foreignNames)})`;
  if (e.kind === 'LetExpression') return `(let ${e.name.name} = ${emitHaskellExpr(e.value, foreignNames)} in ${emitHaskellExpr(e.body, foreignNames)})`;
  throw new Error(`Haskell backend unsupported expression kind: ${expressionKind(e)}`);
}

import { parse } from '../src/parser';
import { checkProgram } from '../src/core/check';
import { emitTypeScript } from '../src/codegen/typescript';
import { emitHaskell } from '../src/codegen/haskell';
import { runLsc } from '../src/cli/lsc';
import * as fs from 'fs';
import path from 'path';
import assert from 'node:assert/strict';

interface FixtureExpectation {
  file: string;
  tsIncludes: string[];
  hsIncludes: string[];
}

function checkFixture(fixture: FixtureExpectation) {
  const fixturePath = path.resolve(__dirname, '../../..', fixture.file);
  const src = fs.readFileSync(fixturePath, 'utf8');
  const pr = parse(src, fixturePath);
  assert.strictEqual(pr.diagnostics.length, 0, `${fixture.file} parse diagnostics`);
  const c = checkProgram(pr.program!);
  assert.strictEqual(c.diagnostics.length, 0, `${fixture.file} check diagnostics`);
  const ts = emitTypeScript(pr.program!);
  const hs = emitHaskell(pr.program!);
  for (const expected of fixture.tsIncludes) {
    assert.ok(ts.includes(expected), `${fixture.file} TypeScript output should include ${expected}`);
  }
  for (const expected of fixture.hsIncludes) {
    assert.ok(hs.includes(expected), `${fixture.file} Haskell output should include ${expected}`);
  }
  const originalError = console.error;
  try {
    console.error = () => {};
    assert.strictEqual(runLsc(['emit', fixturePath, '--target', 'py']), 1, `${fixture.file} should reject py target`);
    assert.strictEqual(runLsc(['emit', fixturePath, '--target', 'python']), 1, `${fixture.file} should reject python target`);
  } finally {
    console.error = originalError;
  }
}

function checkFails(name: string, source: string, expected: string) {
  const pr = parse(source, `${name}.ls`);
  assert.strictEqual(pr.diagnostics.length, 0, `${name} should parse`);
  const c = checkProgram(pr.program!);
  assert.ok(c.diagnostics.some(d => d.message.includes(expected)), `${name} should report ${expected}, got ${c.diagnostics.map(d => d.message).join('; ')}`);
}

function parseFails(name: string, source: string, expected: string) {
  const pr = parse(source, `${name}.ls`);
  assert.ok(pr.diagnostics.some(d => d.message.includes(expected)), `${name} should report ${expected}, got ${pr.diagnostics.map(d => d.message).join('; ')}`);
}

function checkUnsupportedBackendErrors() {
  const badProgram: any = {
    kind: 'Program',
    modules: [
      {
        kind: 'Module',
        name: 'BadBackend',
        declarations: [
          {
            kind: 'Declaration',
            name: { kind: 'Identifier', name: 'bad' },
            value: { kind: 'MysteryExpression' },
          },
        ],
      },
    ],
  };

  assert.throws(
    () => emitTypeScript(badProgram),
    /TypeScript backend unsupported expression kind: MysteryExpression/,
    'TypeScript backend should reject unsupported expression kinds clearly',
  );
  assert.throws(
    () => emitHaskell(badProgram),
    /Haskell backend unsupported expression kind: MysteryExpression/,
    'Haskell backend should reject unsupported expression kinds clearly',
  );
}

function checkHaskellNotEqualEmission() {
  const source = `module Compare

is_not : i32 -> i32 -> bool
is_not x y = x != y
`;
  const pr = parse(source, 'not-equal.ls');
  assert.strictEqual(pr.diagnostics.length, 0, 'not-equal should parse');
  const c = checkProgram(pr.program!);
  assert.strictEqual(c.diagnostics.length, 0, `not-equal should check, got ${c.diagnostics.map(d => d.message).join('; ')}`);

  const ts = emitTypeScript(pr.program!);
  const hs = emitHaskell(pr.program!);
  assert.ok(ts.includes('return (x != y);'), 'TypeScript should preserve LambdaScript != as target-valid !=');
  assert.ok(hs.includes('is_not x y = (x /= y)'), 'Haskell should emit LambdaScript != as /=');
  assert.ok(!hs.includes('!='), 'Haskell output should not contain raw !=');
}

function checkUnsupportedForeignCallPlacement() {
  const source = `module BadForeignPlacement

foreign cpp add_i32 : i32 -> i32 -> i32 = "ls_add_i32"

bad : i32 -> i32
bad x = add_i32(x, 1)
`;
  const pr = parse(source, 'bad-foreign-placement.ls');
  assert.strictEqual(pr.diagnostics.length, 0, 'foreign-placement fixture should parse');
  const c = checkProgram(pr.program!);
  assert.strictEqual(c.diagnostics.length, 0, `foreign-placement fixture should check, got ${c.diagnostics.map(d => d.message).join('; ')}`);

  assert.throws(
    () => emitTypeScript(pr.program!),
    /TypeScript backend unsupported foreign call placement: add_i32/,
    'TypeScript backend should reject foreign calls outside direct top-level declarations',
  );
  assert.throws(
    () => emitHaskell(pr.program!),
    /Haskell backend unsupported foreign call placement: add_i32/,
    'Haskell backend should reject foreign calls outside direct top-level declarations',
  );
}

